async (page) => {
  // Walk directly to Forester
  const move = await page.evaluate(({x, y}) => JSON.stringify(window.__moveTo(x, y)), {x: 216, y: 115});
  await page.waitForTimeout(3000);
  // Talk
  const talk = await page.evaluate((id) => window.__talkToNPC(id), '1-41481128');
  await page.waitForTimeout(1500);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({ move, talk, pos: parsed.player_position, dialogue: parsed.ui_state.npc_dialogue, quest_panel: parsed.ui_state.quest_panel_visible });
}

async (page) => {
  // Navigate west toward goblins
  const result = await page.evaluate(({x,y}) => JSON.stringify(window.__navigateTo(x, y)), {x: 155, y: 160});
  await page.waitForTimeout(8000);
  // Check position and nearby mobs
  const state = await page.evaluate(() => {
    const g = window.__latestGameState;
    return {
      pos: g.player_position, nav: g.navigation,
      mobs: g.nearby_entities.filter(e => e.type === 3).slice(0, 5).map(e => e.name + ' HP:' + e.hp + ' dist:' + e.distance)
    };
  });
  return JSON.stringify(state);
}

